// src/artifacts/js/conditions.ts
import outdent from "outdent";
function generateConditions(ctx) {
  const keys = Object.keys(ctx.conditions.values).concat("base");
  return {
    js: outdent`
    ${ctx.file.import("withoutSpace", "../helpers")}

    const conditionsStr = "${keys.join(",")}"
    const conditions = new Set(conditionsStr.split(','))

    const conditionRegex = /^@|&|&$/

    export function isCondition(value){
      return conditions.has(value) || conditionRegex.test(value)
    }

    const underscoreRegex = /^_/
    const conditionsSelectorRegex = /&|@/

    export function finalizeConditions(paths){
      return paths.map((path) => {
        if (conditions.has(path)){
          return path.replace(underscoreRegex, '')
        }

        if (conditionsSelectorRegex.test(path)){
          return \`[\${withoutSpace(path.trim())}]\`
        }

        return path
      })}

      export function sortConditions(paths){
        return paths.sort((a, b) => {
          const aa = isCondition(a)
          const bb = isCondition(b)
          if (aa && !bb) return 1
          if (!aa && bb) return -1
          return 0
        })
      }
      `,
    dts: outdent`
    ${ctx.file.importType("AnySelector, Selectors", "./selectors")}

    export interface Conditions {
    ${keys.map(
      (key) => `	${key === "base" ? `/** The base (=no conditions) styles to apply  */
` : ctx.conditions.get(key) ? `/** \`${[].concat(ctx.conditions.get(key) ?? "").join(" ")}\` */
` : ""}	${JSON.stringify(key)}: string`
    ).join("\n")}
    }

    export type ConditionalValue<V> =
      | V
      | Array<V | null>
      | {
          [K in keyof Conditions]?: ConditionalValue<V>
        }

    export type Nested<P> = P & {
      [K in Selectors]?: Nested<P>
    } & {
      [K in AnySelector]?: Nested<P>
    } & {
      [K in keyof Conditions]?: Nested<P>
    }

  `
  };
}

// src/artifacts/js/conditions.string-literal.ts
import outdent2 from "outdent";
function generateStringLiteralConditions(ctx) {
  return {
    js: outdent2`
    ${ctx.file.import("withoutSpace", "../helpers")}

    export const isCondition = (val) => condRegex.test(val)

    const condRegex = /^@|&|&$/
    const selectorRegex = /&|@/

    export const finalizeConditions = (paths) => {
      return paths.map((path) => (selectorRegex.test(path) ? \`[\${withoutSpace(path.trim())}]\` : path))
    }

    export function sortConditions(paths){
      return paths.sort((a, b) => {
        const aa = isCondition(a)
        const bb = isCondition(b)
        if (aa && !bb) return 1
        if (!aa && bb) return -1
        return 0
      })
    }
      `,
    dts: outdent2`
  `
  };
}

// src/artifacts/js/css-fn.ts
import { outdent as outdent3 } from "outdent";
function generateCssFn(ctx) {
  const { utility, hash, prefix, conditions } = ctx;
  const { separator, getPropShorthands } = utility;
  return {
    dts: outdent3`
    ${ctx.file.importType("SystemStyleObject", "../types/index")}

    type Styles = SystemStyleObject | undefined | null | false

    interface CssRawFunction {
      (styles: Styles): SystemStyleObject
      (styles: Styles[]): SystemStyleObject
      (...styles: Array<Styles | Styles[]>): SystemStyleObject
      (styles: Styles): SystemStyleObject
    }

    interface CssFunction {
      (styles: Styles): string
      (styles: Styles[]): string
      (...styles: Array<Styles | Styles[]>): string
      (styles: Styles): string

      raw: CssRawFunction
    }

    export declare const css: CssFunction;
    `,
    js: outdent3`
    ${ctx.file.import("createCss, createMergeCss, hypenateProperty, withoutSpace", "../helpers")}
    ${ctx.file.import("sortConditions, finalizeConditions", "./conditions")}

    const utilities = "${utility.entries().map(([prop, className]) => {
      const shorthandList = getPropShorthands(prop);
      const result = [
        prop,
        [
          className,
          shorthandList.length ? (
            // mark shorthand equal to className as 1 to save a few bytes
            shorthandList.map((shorthand) => shorthand === className ? 1 : shorthand).join("/")
          ) : null
        ].filter(Boolean).join("/")
      ].join(":");
      return result;
    }).join(",")}"

    const classNameByProp = new Map()
    ${utility.hasShorthand ? outdent3`
    const shorthands = new Map()
    utilities.split(',').forEach((utility) => {
      const [prop, meta] = utility.split(':')
      const [className, ...shorthandList] = meta.split('/')
      classNameByProp.set(prop, className)
      if (shorthandList.length) {
        shorthandList.forEach((shorthand) => {
          shorthands.set(shorthand === '1' ? className : shorthand, prop)
        })
      }
    })

    const resolveShorthand = (prop) => shorthands.get(prop) || prop
    ` : outdent3`
    utilities.split(',').forEach((utility) => {
      const [prop, className] = utility.split(':')
      classNameByProp.set(prop, className)
    })
    `}

    const context = {
      ${hash.className ? "hash: true," : ""}
      conditions: {
        shift: sortConditions,
        finalize: finalizeConditions,
        breakpoints: { keys: ${JSON.stringify(conditions.breakpoints.keys)} }
      },
      utility: {
        ${prefix.className ? "prefix: " + JSON.stringify(prefix.className) + "," : ""}
        transform: ${utility.hasShorthand ? `(prop, value) => {
              const key = resolveShorthand(prop)
              const propKey = classNameByProp.get(key) || hypenateProperty(key)
              return { className: \`\${propKey}${separator}\${withoutSpace(value)}\` }
            }` : `(key, value) => ({ className: \`\${classNameByProp.get(key) || hypenateProperty(key)}${separator}\${withoutSpace(value)}\` })`},
        ${utility.hasShorthand ? "hasShorthand: true," : ""}
        toHash: ${utility.toHash},
        resolveShorthand: ${utility.hasShorthand ? "resolveShorthand" : "prop => prop"},
      }
    }

    const cssFn = createCss(context)
    export const css = (...styles) => cssFn(mergeCss(...styles))
    css.raw = (...styles) => mergeCss(...styles)

    export const { mergeCss, assignCss } = createMergeCss(context)
    `
  };
}

// src/artifacts/js/css-fn.string-literal.ts
import { outdent as outdent4 } from "outdent";
function generateStringLiteralCssFn(ctx) {
  const { utility, hash, prefix } = ctx;
  const { separator } = utility;
  return {
    dts: outdent4`
    export declare function css(template: { raw: readonly string[] | ArrayLike<string> }): string
    `,
    js: outdent4`
    ${ctx.file.import("astish, createCss, isObject, mergeProps, withoutSpace", "../helpers")}
    ${ctx.file.import("finalizeConditions, sortConditions", "./conditions")}

    function transform(prop, value) {
      const className = \`$\{prop}${separator}$\{withoutSpace(value)}\`
      return { className }
    }

    const context = {
      hash: ${hash.className ? "true" : "false"},
      conditions: {
        shift: sortConditions,
        finalize: finalizeConditions,
        breakpoints: { keys: [] },
      },
      utility: {
        prefix: ${prefix.className ? JSON.stringify(prefix.className) : void 0},
        transform,
        hasShorthand: false,
        toHash: ${utility.toHash},
        resolveShorthand(prop) {
          return prop
        },
      }
    }

    const cssFn = createCss(context)

    const fn = (style) => (isObject(style) ? style : astish(style[0]))
    export const css = (...styles) => cssFn(mergeProps(...styles.filter(Boolean).map(fn)))
    css.raw = (...styles) => mergeProps(...styles.filter(Boolean).map(fn))
    `
  };
}

// src/artifacts/js/cva.ts
import { outdent as outdent5 } from "outdent";
function generateCvaFn(ctx) {
  return {
    js: outdent5`
    ${ctx.file.import("compact, mergeProps, memo, splitProps, uniq", "../helpers")}
    ${ctx.file.import("css, mergeCss", "./css")}

    const defaults = (conf) => ({
      base: {},
      variants: {},
      defaultVariants: {},
      compoundVariants: [],
      ...conf,
    })

    export function cva(config) {
      const { base, variants, defaultVariants, compoundVariants } = defaults(config)
      const getVariantProps = (variants) => ({ ...defaultVariants, ...compact(variants) })

      function resolve(props = {}) {
        const computedVariants = getVariantProps(props)
        let variantCss = { ...base }
        for (const [key, value] of Object.entries(computedVariants)) {
          if (variants[key]?.[value]) {
            variantCss = mergeCss(variantCss, variants[key][value])
          }
        }
        const compoundVariantCss = getCompoundVariantCss(compoundVariants, computedVariants)
        return mergeCss(variantCss, compoundVariantCss)
      }

      function merge(__cva) {
        const override = defaults(__cva.config)
        const variantKeys = uniq(__cva.variantKeys, Object.keys(variants))
        return cva({
          base: mergeCss(base, override.base),
          variants: Object.fromEntries(
            variantKeys.map((key) => [key, mergeCss(variants[key], override.variants[key])]),
          ),
          defaultVariants: mergeProps(defaultVariants, override.defaultVariants),
          compoundVariants: [...compoundVariants, ...override.compoundVariants],
        })
      }

      function cvaFn(props) {
        return css(resolve(props))
      }

      const variantKeys = Object.keys(variants)

      function splitVariantProps(props) {
        return splitProps(props, variantKeys)
      }

      const variantMap = Object.fromEntries(Object.entries(variants).map(([key, value]) => [key, Object.keys(value)]))

      return Object.assign(memo(cvaFn), {
        __cva__: true,
        variantMap,
        variantKeys,
        raw: resolve,
        config,
        merge,
        splitVariantProps,
        getVariantProps
      })
    }

    export function getCompoundVariantCss(compoundVariants, variantMap) {
      let result = {}
      compoundVariants.forEach((compoundVariant) => {
        const isMatching = Object.entries(compoundVariant).every(([key, value]) => {
          if (key === 'css') return true

          const values = Array.isArray(value) ? value : [value]
          return values.some((value) => variantMap[key] === value)
        })

        if (isMatching) {
          result = mergeCss(result, compoundVariant.css)
        }
      })

      return result
    }

    export function assertCompoundVariant(name, compoundVariants, variants, prop) {
      if (compoundVariants.length > 0 && typeof variants?.[prop] === 'object') {
        throw new Error(\`[recipe:\${name}:\${prop}] Conditions are not supported when using compound variants.\`)
      }
    }

    `,
    dts: outdent5`
    ${ctx.file.importType("RecipeCreatorFn", "../types/recipe")}

    export declare const cva: RecipeCreatorFn

    ${ctx.file.exportType("RecipeVariant, RecipeVariantProps", "../types/recipe")}
    `
  };
}

// src/artifacts/js/cx.ts
import outdent6 from "outdent";
function generateCx() {
  return {
    js: outdent6`
    function cx() {
      let str = '',
        i = 0,
        arg

      for (; i < arguments.length; ) {
        if ((arg = arguments[i++]) && typeof arg === 'string') {
          str && (str += ' ')
          str += arg
        }
      }
      return str
    }

    export { cx }
  `,
    dts: outdent6`
       type Argument = string | boolean | null | undefined

       /** Conditionally join classNames into a single string */
       export declare function cx(...args: Argument[]): string
      `
  };
}

